public class AppointmentService : IAppointmentService
{
    private static readonly List<Doctor> Doctors =
    [
        new("Dr. Smith", AcceptsSelfPay: false),
        new("Dr. Johnson", AcceptsSelfPay: true),
        new("Dr. Patel", AcceptsSelfPay: true),
        new("Dr. Lee", AcceptsSelfPay: false),
    ];

    private static readonly List<string> AllSlots =
    [
        "9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM",
